package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Build;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.view.Gravity;
import android.view.ViewGroup;
import android.webkit.MimeTypeMap;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.IOException;
import java.io.InputStream;

public class DocumentViewActivity extends AppCompatActivity {

    private FrameLayout rootView;
    private ImageView imageView;
    private TextView messageView;
    private ParcelFileDescriptor pdfFileDescriptor;
    private PdfRenderer pdfRenderer;
    private PdfRenderer.Page currentPage;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        rootView = new FrameLayout(this);

        imageView = new ImageView(this);
        imageView.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        imageView.setAdjustViewBounds(true);

        messageView = new TextView(this);
        FrameLayout.LayoutParams messageParams = new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.WRAP_CONTENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        );
        messageParams.gravity = Gravity.CENTER;
        messageView.setLayoutParams(messageParams);
        messageView.setTextSize(16f);

        rootView.addView(imageView);
        rootView.addView(messageView);

        setContentView(rootView);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        closePdf();
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null || !Intent.ACTION_VIEW.equals(intent.getAction())) {
            showMessage("No document to display.");
            return;
        }

        Uri fileUri = intent.getData();
        if (fileUri == null) {
            showMessage("Invalid document URI.");
            return;
        }

        getWindow().getDecorView().post(() -> displayDocument(fileUri, intent.getType()));
    }

    private void displayDocument(Uri fileUri, @Nullable String providedMimeType) {
        String mimeType = providedMimeType;
        if (mimeType == null) {
            mimeType = resolveMimeType(fileUri);
        }

        if (mimeType == null) {
            mimeType = "";
        }

        if ("application/pdf".equalsIgnoreCase(mimeType) || isPdfUri(fileUri)) {
            displayPdf(fileUri);
        } else if (mimeType.startsWith("image/")) {
            displayImage(fileUri);
        } else {
            showMessage("Unsupported document type.");
        }
    }

    private void displayImage(Uri fileUri) {
        closePdf();
        try (InputStream inputStream = getContentResolver().openInputStream(fileUri)) {
            if (inputStream == null) {
                showMessage("Unable to open image.");
                return;
            }
            Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
            if (bitmap == null) {
                showMessage("Unable to decode image.");
                return;
            }
            imageView.setImageBitmap(bitmap);
            imageView.setVisibility(ImageView.VISIBLE);
            messageView.setVisibility(TextView.GONE);
        } catch (IOException e) {
            showMessage("Failed to load image.");
        }
    }

    private void displayPdf(Uri fileUri) {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.LOLLIPOP) {
            showMessage("PDF viewing is not supported on this device.");
            return;
        }

        closePdf();

        try {
            pdfFileDescriptor = getContentResolver().openFileDescriptor(fileUri, "r");
            if (pdfFileDescriptor == null) {
                showMessage("Unable to open PDF.");
                return;
            }

            pdfRenderer = new PdfRenderer(pdfFileDescriptor);
            if (pdfRenderer.getPageCount() <= 0) {
                showMessage("PDF has no pages.");
                return;
            }

            currentPage = pdfRenderer.openPage(0);

            int width = Math.max(1, currentPage.getWidth() * 2);
            int height = Math.max(1, currentPage.getHeight() * 2);
            Bitmap bitmap = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888);
            bitmap.eraseColor(0xFFFFFFFF);
            currentPage.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);

            imageView.setImageBitmap(bitmap);
            imageView.setVisibility(ImageView.VISIBLE);
            messageView.setVisibility(TextView.GONE);
        } catch (IOException e) {
            showMessage("Failed to load PDF.");
        }
    }

    private String resolveMimeType(Uri uri) {
        ContentResolver resolver = getContentResolver();
        String mimeType = resolver.getType(uri);
        if (mimeType != null) {
            return mimeType;
        }

        String extension = MimeTypeMap.getFileExtensionFromUrl(uri.toString());
        if (extension != null && !extension.isEmpty()) {
            return MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension.toLowerCase());
        }

        return null;
    }

    private boolean isPdfUri(Uri uri) {
        String value = uri.toString().toLowerCase();
        return value.endsWith(".pdf");
    }

    private void showMessage(String message) {
        imageView.setImageDrawable(null);
        imageView.setVisibility(ImageView.GONE);
        messageView.setText(message);
        messageView.setVisibility(TextView.VISIBLE);
    }

    private void closePdf() {
        if (currentPage != null) {
            currentPage.close();
            currentPage = null;
        }
        if (pdfRenderer != null) {
            pdfRenderer.close();
            pdfRenderer = null;
        }
        if (pdfFileDescriptor != null) {
            try {
                pdfFileDescriptor.close();
            } catch (IOException ignored) {
            }
            pdfFileDescriptor = null;
        }
    }

    @Override
    protected void onDestroy() {
        closePdf();
        super.onDestroy();
    }
}

